import{_ as r,o as l,c as t,a0 as e,j as o,a as i}from"./chunks/framework.BjpW4enL.js";const _=JSON.parse('{"title":"T3 Fluxo: Formalização Inicial","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/T3_FLUXO_FORMALIZACAO_INICIAL.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/T3_FLUXO_FORMALIZACAO_INICIAL.md","lastUpdated":1783623176000}'),s={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/T3_FLUXO_FORMALIZACAO_INICIAL.md"};function d(c,a,n,u,p,m){return l(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="t3-fluxo-formalizacao-inicial" tabindex="-1">T3 Fluxo: Formalização Inicial <a class="header-anchor" href="#t3-fluxo-formalizacao-inicial" aria-label="Permalink to &quot;T3 Fluxo: Formalização Inicial&quot;">​</a></h1><p><strong>Status</strong>: Fronteira de pesquisa conceitual<br><strong>Data</strong>: 2026-03-18</p><p>&gt; Este documento aprofunda a nota &gt; <a href="/var/home/bruno/NEXUS/docs/architecture_decisions/GEOMETRIA_DE_FLUXO_T3.html">GEOMETRIA_DE_FLUXO_T3.md</a>. &gt; Ele não fixa ainda um modelo matemático final. &gt; Ele propõe um vocabulário formal mínimo para distância, operadores e métricas de fluxo.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Definir uma base formal pequena o bastante para ser útil e grande o bastante para:</p><ul><li>preservar os conceitos centrais da hipótese de fluxo;</li><li>permitir tradução posterior para grafo discreto;</li><li>impedir regressão para retrieval puramente linear.</li></ul><h2 id="estruturas-minimas" tabindex="-1">Estruturas mínimas <a class="header-anchor" href="#estruturas-minimas" aria-label="Permalink to &quot;Estruturas mínimas&quot;">​</a></h2><h3 id="espaco-expressivo" tabindex="-1">Espaço expressivo <a class="header-anchor" href="#espaco-expressivo" aria-label="Permalink to &quot;Espaço expressivo&quot;">​</a></h3><p>Seja <code>T3</code> um espaço expressivo <code>X</code>, contínuo ou discretizado, no qual cada estado <code>x</code> representa:</p><ul><li>um artefato,</li><li>um regime computacional,</li><li>ou uma posição contextual local.</li></ul><h3 id="malha-topologica" tabindex="-1">Malha topológica <a class="header-anchor" href="#malha-topologica" aria-label="Permalink to &quot;Malha topológica&quot;">​</a></h3><p>Seja <code>G = (V, E)</code> uma malha discreta sobre <code>X</code>, onde:</p><ul><li><code>V</code> são estados materializados;</li><li><code>E</code> são relações de travessia ou transformação;</li><li>cada aresta <code>e = (u, v)</code> carrega estrutura adicional.</li></ul><h3 id="query" tabindex="-1">Query <a class="header-anchor" href="#query" aria-label="Permalink to &quot;Query&quot;">​</a></h3><p>A query <code>q</code> não é apenas um vetor de busca. Ela é tratada como operador de excitação que induz:</p><ul><li>um campo local sobre <code>X</code>;</li><li>ou, na forma discreta, uma redistribuição de pesos sobre <code>E</code> e <code>V</code>.</li></ul><h2 id="distancia" tabindex="-1">Distância <a class="header-anchor" href="#distancia" aria-label="Permalink to &quot;Distância&quot;">​</a></h2><h2 id="requisito" tabindex="-1">Requisito <a class="header-anchor" href="#requisito" aria-label="Permalink to &quot;Requisito&quot;">​</a></h2><p>A distância relevante para o NEXUS não precisa coincidir com:</p><ul><li>distância euclidiana,</li><li>similaridade cosseno,</li><li>ou menor caminho topológico puro.</li></ul><p>Ela pode ser uma distância composta:</p><p>[ d_q(u, v) = \\alpha, d_s(u, v) + \\beta, d_t(u, v) + \\chi, d_v(u, v) + \\delta, d_c(u, v) ]</p><p>Onde, por exemplo:</p><ul><li><code>d_s</code>: separação semântica local;</li><li><code>d_t</code>: separação topológica;</li><li><code>d_v</code>: separação temporal/versional;</li><li><code>d_c</code>: custo contextual de reidratação.</li></ul><h2 id="leitura" tabindex="-1">Leitura <a class="header-anchor" href="#leitura" aria-label="Permalink to &quot;Leitura&quot;">​</a></h2><p>A distância pode depender da query <code>q</code>. Isso significa que o espaço navegável é, em princípio, dependente do regime consultado.</p><h2 id="operadores" tabindex="-1">Operadores <a class="header-anchor" href="#operadores" aria-label="Permalink to &quot;Operadores&quot;">​</a></h2><h3 id="_1-operador-de-incidencia" tabindex="-1">1. Operador de incidência <a class="header-anchor" href="#_1-operador-de-incidencia" aria-label="Permalink to &quot;1. Operador de incidência&quot;">​</a></h3><p>[ \\mathcal{I}_q : X \\rightarrow \\mathbb{R} ]</p><p>Mede quanto a query incide localmente sobre cada estado.</p><p>No discreto:</p><p>[ \\mathcal{I}_q(v) ]</p><p>é a massa inicial ou relevância inicial do nó <code>v</code>.</p><h3 id="_2-operador-de-propagacao" tabindex="-1">2. Operador de propagação <a class="header-anchor" href="#_2-operador-de-propagacao" aria-label="Permalink to &quot;2. Operador de propagação&quot;">​</a></h3><p>[ \\mathcal{P}_q : \\mathbb{R}^{|V|} \\rightarrow \\mathbb{R}^{|V|} ]</p><p>Propaga a incidência inicial pela malha, respeitando pesos, direção e custo.</p><p>Ele cobre, em espírito:</p><ul><li>walks topológicos,</li><li>PageRank personalizado,</li><li>difusão restrita,</li><li>e expansões condicionadas por contexto.</li></ul><h3 id="_3-operador-de-reidratacao" tabindex="-1">3. Operador de reidratação <a class="header-anchor" href="#_3-operador-de-reidratacao" aria-label="Permalink to &quot;3. Operador de reidratação&quot;">​</a></h3><p>[ \\mathcal{R} : V \\rightarrow C ]</p><p>Transforma estados relevantes em contexto materializável:</p><ul><li>chunks,</li><li>packs,</li><li>blobs,</li><li>versões,</li><li>documentação associada.</li></ul><h3 id="_4-operador-de-compressao" tabindex="-1">4. Operador de compressão <a class="header-anchor" href="#_4-operador-de-compressao" aria-label="Permalink to &quot;4. Operador de compressão&quot;">​</a></h3><p>[ \\mathcal{K} : C^* \\rightarrow W ]</p><p>Transforma o conjunto de contexto materializado numa janela legível e útil para a LLM.</p><h2 id="caminhos" tabindex="-1">Caminhos <a class="header-anchor" href="#caminhos" aria-label="Permalink to &quot;Caminhos&quot;">​</a></h2><p>Um caminho discreto é:</p><p>[ \\gamma = (v_0, v_1, \\dots, v_n) ]</p><p>com custo acumulado:</p>',49),o("p",null,[i("[ \\mathcal{J}"),o("em",{i:"0"},"q(\\gamma) = \\sum"),i("^{n-1} w_q(v_i, v_{i+1}) ]")],-1),e('<p>Onde <code>w_q</code> pode combinar:</p><ul><li>distância composta;</li><li>coerência local;</li><li>continuidade temporal;</li><li>penalidade de salto;</li><li>ganho contextual esperado.</li></ul><h2 id="fluxo" tabindex="-1">Fluxo <a class="header-anchor" href="#fluxo" aria-label="Permalink to &quot;Fluxo&quot;">​</a></h2><h2 id="definicao-minima" tabindex="-1">Definição mínima <a class="header-anchor" href="#definicao-minima" aria-label="Permalink to &quot;Definição mínima&quot;">​</a></h2><p>Fluxo é a quantidade de massa contextual transferida por uma aresta, caminho ou região sob a query <code>q</code>.</p><p>No discreto:</p><p>[ \\Phi_q(e) ]</p><p>é o fluxo atravessando a aresta <code>e</code>.</p><h2 id="metricas-iniciais" tabindex="-1">Métricas iniciais <a class="header-anchor" href="#metricas-iniciais" aria-label="Permalink to &quot;Métricas iniciais&quot;">​</a></h2><h3 id="_1-densidade-de-regiao" tabindex="-1">1. Densidade de região <a class="header-anchor" href="#_1-densidade-de-regiao" aria-label="Permalink to &quot;1. Densidade de região&quot;">​</a></h3><p>[ \\rho_q(R) = \\sum_{v \\in R} \\mathcal{I}_q(v) ]</p><p>Mede a concentração de incidência numa região <code>R</code>.</p><h3 id="_2-fluxo-de-aresta" tabindex="-1">2. Fluxo de aresta <a class="header-anchor" href="#_2-fluxo-de-aresta" aria-label="Permalink to &quot;2. Fluxo de aresta&quot;">​</a></h3><p>[ \\Phi_q(u, v) ]</p><p>Mede quanta massa atravessa a aresta <code>(u, v)</code> após propagação.</p><h3 id="_3-divergencia-local" tabindex="-1">3. Divergência local <a class="header-anchor" href="#_3-divergencia-local" aria-label="Permalink to &quot;3. Divergência local&quot;">​</a></h3><p>Se um nó redistribui massa em excesso para fora de sua vizinhança, há divergência alta. Isso pode indicar:</p><ul><li>ruído,</li><li>dispersão,</li><li>ou quebra de coerência.</li></ul><h3 id="_4-convergencia-local" tabindex="-1">4. Convergência local <a class="header-anchor" href="#_4-convergencia-local" aria-label="Permalink to &quot;4. Convergência local&quot;">​</a></h3><p>Se massa demais colapsa em poucos polos, há convergência alta. Isso pode indicar:</p><ul><li>foco útil,</li><li>ou buraco negro semântico.</li></ul><h3 id="_5-recorrencia-orbital" tabindex="-1">5. Recorrência orbital <a class="header-anchor" href="#_5-recorrencia-orbital" aria-label="Permalink to &quot;5. Recorrência orbital&quot;">​</a></h3><p>Mede o quanto um caminho retorna a regiões equivalentes sob deslocamento de estado. Isso ajuda a distinguir:</p><ul><li>repetição improdutiva;</li><li>revisitação estruturalmente fértil.</li></ul><h3 id="_6-deriva-de-query" tabindex="-1">6. Deriva de query <a class="header-anchor" href="#_6-deriva-de-query" aria-label="Permalink to &quot;6. Deriva de query&quot;">​</a></h3><p>Mede quanto a trajetória se afasta do regime inicialmente excitado pela query.</p><h2 id="sequencial-e-paralelo" tabindex="-1">Sequencial e paralelo <a class="header-anchor" href="#sequencial-e-paralelo" aria-label="Permalink to &quot;Sequencial e paralelo&quot;">​</a></h2><h3 id="regime-sequencial" tabindex="-1">Regime sequencial <a class="header-anchor" href="#regime-sequencial" aria-label="Permalink to &quot;Regime sequencial&quot;">​</a></h3><p>A massa contextual segue um caminho dominante ou pequeno feixe de caminhos dominantes.</p><p>Uso natural:</p><ul><li>paginação,</li><li>explicabilidade,</li><li>montagem incremental de packs.</li></ul><h3 id="regime-paralelo" tabindex="-1">Regime paralelo <a class="header-anchor" href="#regime-paralelo" aria-label="Permalink to &quot;Regime paralelo&quot;">​</a></h3><p>A massa contextual propaga por múltiplas regiões ao mesmo tempo.</p><p>Uso natural:</p><ul><li>amplitude analítica;</li><li>queries compostas;</li><li>transferência entre casos estruturalmente distantes.</li></ul><h2 id="leitura-geometrica" tabindex="-1">Leitura geométrica <a class="header-anchor" href="#leitura-geometrica" aria-label="Permalink to &quot;Leitura geométrica&quot;">​</a></h2><p>Esta formalização admite que diferentes fenômenos possam ser vistos como variações de métrica e trajetória:</p><ul><li>linha: progressão simples;</li><li>ciclo: recorrência;</li><li>hélice/cilindro: recorrência com deslocamento axial;</li><li>esfera: fechamento local com múltiplas direções;</li><li>malha híbrida: mistura de retorno, desvio e transferência.</li></ul><p>Assim, fenômenos que parecem distantes podem ser apenas expressões distintas de:</p><ul><li>uma mesma dinâmica;</li><li>sob outra distância;</li><li>com outro operador;</li><li>em outra geometria local.</li></ul><h2 id="traducao-para-o-runtime-atual" tabindex="-1">Tradução para o runtime atual <a class="header-anchor" href="#traducao-para-o-runtime-atual" aria-label="Permalink to &quot;Tradução para o runtime atual&quot;">​</a></h2><p>No estado atual do NEXUS, a tradução mais conservadora desta formalização seria:</p><ul><li><code>\\mathcal{I}_q</code>: score inicial vindo de T3;</li><li><code>\\mathcal{P}_q</code>: expansão topológica em T4;</li><li><code>\\mathcal{R}</code>: materialização em packs via T2;</li><li><code>\\mathcal{K}</code>: montagem final da janela de contexto.</li></ul><p>Ou seja: a arquitetura atual já possui os lugares onde essa formalização poderia se encaixar, mesmo de maneira rudimentar.</p><h2 id="questoes-abertas" tabindex="-1">Questões abertas <a class="header-anchor" href="#questoes-abertas" aria-label="Permalink to &quot;Questões abertas&quot;">​</a></h2><ul><li>Qual subconjunto de métricas é suficiente para primeiro experimento?</li><li>Quais componentes devem entrar na distância composta?</li><li>Como distinguir recorrência útil de ciclo espúrio?</li><li>Quando priorizar fluxo paralelo em vez de caminho dominante?</li><li>Quanto desse modelo deve viver em T3, T4 ou no coordinator?</li></ul><h2 id="proximo-passo-recomendado" tabindex="-1">Próximo passo recomendado <a class="header-anchor" href="#proximo-passo-recomendado" aria-label="Permalink to &quot;Próximo passo recomendado&quot;">​</a></h2><p>O menor próximo passo implementável não é resolver toda a geometria. É escolher um experimento com três medições:</p><ul><li><code>edge_flow</code></li><li><code>region_density</code></li><li><code>query_drift</code></li></ul><p>Essas três já permitiriam observar se a query produz:</p><ul><li>campo coerente,</li><li>dispersão excessiva,</li><li>ou colapso em polos ruins.</li></ul><h2 id="leituras-de-apoio" tabindex="-1">Leituras de apoio <a class="header-anchor" href="#leituras-de-apoio" aria-label="Permalink to &quot;Leituras de apoio&quot;">​</a></h2><ul><li><a href="/var/home/bruno/NEXUS/docs/architecture_decisions/GEOMETRIA_DE_FLUXO_T3.html">GEOMETRIA_DE_FLUXO_T3.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/CANONICAL_RUNTIME.html">CANONICAL_RUNTIME.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/CANONICAL_T4.html">CANONICAL_T4.md</a></li><li><a href="/var/home/bruno/NEXUS/docs/architecture_decisions/REFATORACAO_MEMORIA_OPERACIONAL.html">REFATORACAO_MEMORIA_OPERACIONAL.md</a></li></ul>',53)])])}const q=r(s,[["render",d]]);export{_ as __pageData,q as default};
